/**
 * Heatmap Fragment Shader
 *
 * Renders schedule density as a color gradient.
 * Used for LOD 0 (very zoomed out view - years visible).
 *
 * The density data is passed as a uniform array representing
 * the number of maintenance blocks per time bucket.
 */

precision mediump float;

// Uniforms
uniform vec2 uResolution;      // Viewport dimensions
uniform float uRowHeight;      // Height of each train row
uniform int uNumRows;          // Number of train rows
uniform int uNumBuckets;       // Number of time buckets
uniform sampler2D uDensityTex; // Density texture (row x bucket)
uniform float uMaxDensity;     // Max density for normalization

// Varyings from vertex shader
varying vec2 vTextureCoord;

// Color palette for heatmap (cold to hot)
vec3 heatmapColor(float t) {
    // Smooth gradient from dark blue -> cyan -> yellow -> red
    vec3 cold = vec3(0.1, 0.1, 0.3);   // Dark blue
    vec3 mid1 = vec3(0.0, 0.6, 0.7);   // Cyan
    vec3 mid2 = vec3(0.9, 0.8, 0.2);   // Yellow
    vec3 hot = vec3(0.9, 0.2, 0.2);    // Red

    if (t < 0.33) {
        return mix(cold, mid1, t * 3.0);
    } else if (t < 0.66) {
        return mix(mid1, mid2, (t - 0.33) * 3.0);
    } else {
        return mix(mid2, hot, (t - 0.66) * 3.0);
    }
}

void main() {
    // Get normalized density from texture
    float density = texture2D(uDensityTex, vTextureCoord).r;

    // Normalize by max density
    float normalizedDensity = clamp(density / uMaxDensity, 0.0, 1.0);

    // Apply gamma correction for better visual distribution
    float gamma = 0.6;
    float adjustedDensity = pow(normalizedDensity, gamma);

    // Get color from heatmap palette
    vec3 color = heatmapColor(adjustedDensity);

    // Add subtle grid lines for row separation
    float rowY = mod(gl_FragCoord.y, uRowHeight);
    float gridAlpha = smoothstep(0.0, 1.0, rowY) * smoothstep(uRowHeight, uRowHeight - 1.0, rowY);

    // Apply grid darkening at row boundaries
    color *= mix(0.8, 1.0, gridAlpha);

    // Output final color
    gl_FragColor = vec4(color, 1.0);
}

/**
 * Heatmap Vertex Shader
 *
 * Simple passthrough for fullscreen quad.
 */

precision mediump float;

attribute vec2 aVertexPosition;
attribute vec2 aTextureCoord;

uniform mat3 uProjectionMatrix;

varying vec2 vTextureCoord;

void main() {
    gl_Position = vec4((uProjectionMatrix * vec3(aVertexPosition, 1.0)).xy, 0.0, 1.0);
    vTextureCoord = aTextureCoord;
}

