import { Application, Container, Graphics } from 'pixi.js';
import { getViewportState, subscribeViewport, type ViewportState } from '../engine/store/viewportStore';
import { getSimulationState, subscribeSimulation } from '../engine/store/simulationStore';
import { HeatmapLayer } from './layers/HeatmapLayer';

/**
 * FractalRenderer - High-performance PixiJS renderer with LOD layers.
 *
 * Manages the PixiJS Application and three distinct rendering layers:
 * - LOD 0: Heatmap (GPU shader-based)
 * - LOD 1: Stacked bars (instanced rendering)
 * - LOD 2: Detailed capsules with text
 *
 * Integrates with Zustand stores for reactive viewport/data updates.
 */

export interface FractalRendererConfig {
  /** Row height in pixels for train lanes */
  rowHeight: number;
  /** Background color */
  backgroundColor: number;
  /** Enable debug overlay */
  debug: boolean;
}

const DEFAULT_CONFIG: FractalRendererConfig = {
  rowHeight: 40,
  backgroundColor: 0x1a1a2e,
  debug: false,
};

export class FractalRenderer {
  private app: Application | null = null;
  private isInitialized = false;

  /** Layer containers for each LOD */
  private lod0Container: Container | null = null;
  private lod1Container: Container | null = null;
  private lod2Container: Container | null = null;

  /** Grid overlay for debugging */
  private gridOverlay: Graphics | null = null;

  /** LOD layer instances */
  private heatmapLayer: HeatmapLayer | null = null;

  /** Store unsubscribe functions */
  private unsubscribeViewport: (() => void) | null = null;
  private unsubscribeSimulation: (() => void) | null = null;

  /** Render loop state */
  private rafId: number | null = null;
  private needsRender = true;

  /** Configuration */
  private config: FractalRendererConfig;

  /** Cache for last viewport state (avoid unnecessary re-renders) */
  private lastViewport: Partial<ViewportState> = {};

  constructor(config: Partial<FractalRendererConfig> = {}) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Initialize the PixiJS Application and mount to container.
   */
  async init(container: HTMLElement): Promise<void> {
    if (this.isInitialized) {
      console.warn('FractalRenderer already initialized');
      return;
    }

    // Create PixiJS Application with WebGL preference
    this.app = new Application();

    await this.app.init({
      background: this.config.backgroundColor,
      resizeTo: container,
      antialias: true,
      resolution: window.devicePixelRatio || 1,
      autoDensity: true,
      powerPreference: 'high-performance',
    });

    // Append canvas to container
    container.appendChild(this.app.canvas);

    // Set canvas style for proper sizing
    this.app.canvas.style.width = '100%';
    this.app.canvas.style.height = '100%';
    this.app.canvas.style.display = 'block';

    // Create layer hierarchy
    this.createLayers();

    // Subscribe to store updates
    this.subscribeToStores();

    // Update viewport dimensions
    const { width, height } = this.app.screen;
    getViewportState().setDimensions(width, height);

    // Start render loop
    this.startRenderLoop();

    this.isInitialized = true;
    console.log('[FractalRenderer] Initialized', { width, height });
  }

  /**
   * Create container hierarchy for LOD layers.
   */
  private createLayers(): void {
    if (!this.app) return;

    // LOD 0: Heatmap layer (bottom)
    this.lod0Container = new Container();
    this.lod0Container.label = 'lod0-heatmap';
    this.app.stage.addChild(this.lod0Container);

    // Initialize heatmap layer
    this.heatmapLayer = new HeatmapLayer({ rowHeight: this.config.rowHeight });
    this.lod0Container.addChild(this.heatmapLayer.getContainer());

    // LOD 1: Bars layer (middle)
    this.lod1Container = new Container();
    this.lod1Container.label = 'lod1-bars';
    this.app.stage.addChild(this.lod1Container);

    // LOD 2: Capsules layer (top)
    this.lod2Container = new Container();
    this.lod2Container.label = 'lod2-capsules';
    this.app.stage.addChild(this.lod2Container);

    // Debug grid overlay (always on top)
    if (this.config.debug) {
      this.gridOverlay = new Graphics();
      this.gridOverlay.label = 'debug-grid';
      this.app.stage.addChild(this.gridOverlay);
    }

    // Initial placeholder content
    this.drawPlaceholder();
  }

  /**
   * Draw placeholder content showing layers are working.
   */
  private drawPlaceholder(): void {
    if (!this.app || !this.lod1Container) return;

    const { width, height } = this.app.screen;
    const { rowHeight } = this.config;

    // Draw train lane backgrounds
    const lanes = new Graphics();
    const numLanes = Math.ceil(height / rowHeight);

    for (let i = 0; i < numLanes; i++) {
      const y = i * rowHeight;
      const color = i % 2 === 0 ? 0x16213e : 0x1a1a2e;
      lanes.rect(0, y, width, rowHeight);
      lanes.fill({ color, alpha: 0.5 });
    }

    this.lod1Container.addChild(lanes);
  }

  /**
   * Subscribe to Zustand stores for reactive updates.
   */
  private subscribeToStores(): void {
    // Viewport changes trigger re-render
    this.unsubscribeViewport = subscribeViewport((state) => {
      // Only mark dirty if relevant properties changed
      if (
        state.scale !== this.lastViewport.scale ||
        state.offsetX !== this.lastViewport.offsetX ||
        state.offsetY !== this.lastViewport.offsetY ||
        state.lod !== this.lastViewport.lod
      ) {
        this.lastViewport = {
          scale: state.scale,
          offsetX: state.offsetX,
          offsetY: state.offsetY,
          lod: state.lod,
        };
        this.needsRender = true;
      }
    });

    // Simulation data changes trigger re-render
    this.unsubscribeSimulation = subscribeSimulation(() => {
      this.needsRender = true;
      if (this.heatmapLayer) {
        this.heatmapLayer.markDirty();
      }
    });
  }

  /**
   * Main render loop using requestAnimationFrame.
   */
  private startRenderLoop(): void {
    const render = (): void => {
      if (!this.isInitialized || !this.app) return;

      if (this.needsRender) {
        this.render();
        this.needsRender = false;
      }

      this.rafId = requestAnimationFrame(render);
    };

    this.rafId = requestAnimationFrame(render);
  }

  /**
   * Render current frame based on viewport and LOD.
   */
  private render(): void {
    if (!this.app) return;

    const viewport = getViewportState();
    const simulation = getSimulationState();

    // Update layer visibility based on LOD
    this.updateLodVisibility(viewport.lod);

    // Update viewport transform on stage
    this.updateStageTransform(viewport);

    // Update active LOD layer
    if (viewport.lod === 0 && this.heatmapLayer) {
      this.heatmapLayer.update();
    }

    // Render debug grid if enabled
    if (this.config.debug && this.gridOverlay) {
      this.renderDebugGrid(viewport);
    }

    // Log render stats periodically
    if (this.config.debug && Math.random() < 0.01) {
      console.log('[FractalRenderer] Render', {
        lod: viewport.lod,
        scale: viewport.scale.toExponential(2),
        blocks: simulation.schedule.count,
      });
    }
  }

  /**
   * Update visibility of LOD layers.
   */
  private updateLodVisibility(currentLod: 0 | 1 | 2): void {
    if (this.lod0Container) this.lod0Container.visible = currentLod === 0;
    if (this.lod1Container) this.lod1Container.visible = currentLod === 1;
    if (this.lod2Container) this.lod2Container.visible = currentLod === 2;
  }

  /**
   * Update stage transform based on viewport offset.
   */
  private updateStageTransform(viewport: ViewportState): void {
    if (!this.app) return;

    // Apply virtual scroll offset to stage
    // Note: We only apply Y offset to stage; X is handled per-block for precision
    this.app.stage.y = viewport.offsetY;
  }

  /**
   * Render debug grid showing time divisions.
   */
  private renderDebugGrid(viewport: ViewportState): void {
    if (!this.gridOverlay || !this.app) return;

    this.gridOverlay.clear();

    const { width, height } = this.app.screen;

    // Draw vertical lines every 100 pixels
    this.gridOverlay.stroke({ width: 1, color: 0x333333 });
    for (let x = 0; x < width; x += 100) {
      this.gridOverlay.moveTo(x, 0);
      this.gridOverlay.lineTo(x, height);
    }

    // Draw horizontal lines for train lanes
    for (let y = 0; y < height; y += this.config.rowHeight) {
      this.gridOverlay.moveTo(0, y);
      this.gridOverlay.lineTo(width, y);
    }

    this.gridOverlay.stroke();

    // Draw LOD indicator
    const lodColors = [0xff6b6b, 0x4ecdc4, 0x45b7d1];
    this.gridOverlay.circle(width - 30, 30, 15);
    this.gridOverlay.fill({ color: lodColors[viewport.lod] });
  }

  /**
   * Force a re-render on next frame.
   */
  markDirty(): void {
    this.needsRender = true;
  }

  /**
   * Resize the renderer to fit container.
   */
  resize(width: number, height: number): void {
    if (!this.app) return;

    this.app.renderer.resize(width, height);
    getViewportState().setDimensions(width, height);
    this.needsRender = true;
  }

  /**
   * Get the LOD layer container for external rendering.
   */
  getLodContainer(lod: 0 | 1 | 2): Container | null {
    switch (lod) {
      case 0: return this.lod0Container;
      case 1: return this.lod1Container;
      case 2: return this.lod2Container;
    }
  }

  /**
   * Get the PixiJS Application instance.
   */
  getApp(): Application | null {
    return this.app;
  }

  /**
   * Check if renderer is initialized.
   */
  isReady(): boolean {
    return this.isInitialized;
  }

  /**
   * Clean up and destroy the renderer.
   */
  destroy(): void {
    if (this.rafId !== null) {
      cancelAnimationFrame(this.rafId);
      this.rafId = null;
    }

    if (this.unsubscribeViewport) {
      this.unsubscribeViewport();
      this.unsubscribeViewport = null;
    }

    if (this.unsubscribeSimulation) {
      this.unsubscribeSimulation();
      this.unsubscribeSimulation = null;
    }

    if (this.heatmapLayer) {
      this.heatmapLayer.destroy();
      this.heatmapLayer = null;
    }

    if (this.app) {
      this.app.destroy(true, { children: true, texture: true });
      this.app = null;
    }

    this.lod0Container = null;
    this.lod1Container = null;
    this.lod2Container = null;
    this.gridOverlay = null;
    this.isInitialized = false;

    console.log('[FractalRenderer] Destroyed');
  }
}

/** Singleton instance for global access */
let rendererInstance: FractalRenderer | null = null;

/**
 * Get or create the global FractalRenderer instance.
 */
export function getRenderer(): FractalRenderer {
  if (!rendererInstance) {
    rendererInstance = new FractalRenderer();
  }
  return rendererInstance;
}

/**
 * Destroy the global renderer instance.
 */
export function destroyRenderer(): void {
  if (rendererInstance) {
    rendererInstance.destroy();
    rendererInstance = null;
  }
}

