import { Container, Sprite, Texture, SCALE_MODES } from 'pixi.js';
import { getSimulationState } from '../../engine/store/simulationStore';
import { getViewportState } from '../../engine/store/viewportStore';

/**
 * HeatmapLayer - LOD 0 renderer for very zoomed out views.
 *
 * Aggregates schedule blocks into time buckets and renders
 * density as a color heatmap using GPU-accelerated texture sampling.
 *
 * Performance: Pre-computes density texture once per data change,
 * then renders using simple sprite with texture lookup.
 */

export interface HeatmapConfig {
  /** Number of time buckets across viewport */
  numBuckets: number;
  /** Row height in pixels */
  rowHeight: number;
  /** Number of train rows */
  numRows: number;
}

const DEFAULT_CONFIG: HeatmapConfig = {
  numBuckets: 256,
  rowHeight: 40,
  numRows: 128,
};

/** Color palette for heatmap (cold to hot) */
const HEATMAP_COLORS = [
  0x1a1a2e, // 0: Empty - dark blue/purple
  0x16213e, // 1: Very low
  0x0f4c5c, // 2: Low - teal
  0x00a896, // 3: Medium-low - cyan
  0x3ddc84, // 4: Medium - green
  0xffc93c, // 5: Medium-high - yellow
  0xff6b35, // 6: High - orange
  0xd62828, // 7: Very high - red
] as const;

export class HeatmapLayer {
  private container: Container;
  private sprite: Sprite | null = null;
  private densityData: Float32Array;
  private texture: Texture | null = null;
  private config: HeatmapConfig;
  private isDirty = true;

  constructor(config: Partial<HeatmapConfig> = {}) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.container = new Container();
    this.container.label = 'heatmap-layer';

    // Pre-allocate density array (rows × buckets)
    this.densityData = new Float32Array(this.config.numRows * this.config.numBuckets);
  }

  /**
   * Get the container for adding to stage.
   */
  getContainer(): Container {
    return this.container;
  }

  /**
   * Mark layer as needing recalculation.
   */
  markDirty(): void {
    this.isDirty = true;
  }

  /**
   * Update and render the heatmap.
   */
  update(): void {
    if (!this.isDirty) return;

    this.computeDensity();
    this.updateTexture();
    this.isDirty = false;
  }

  /**
   * Compute density from schedule data.
   * Aggregates blocks into time buckets per train row.
   */
  private computeDensity(): void {
    const { schedule } = getSimulationState();
    const viewport = getViewportState();
    const { numBuckets, numRows } = this.config;

    // Reset density array
    this.densityData.fill(0);

    if (schedule.count === 0) return;

    // Calculate visible time range
    const { originTime, scale, offsetX, width } = viewport;
    const startTime = (0 - offsetX) / scale + originTime;
    const endTime = (width - offsetX) / scale + originTime;
    const timeRange = endTime - startTime;
    const bucketDuration = timeRange / numBuckets;

    // Aggregate blocks into buckets
    for (let i = 0; i < schedule.count; i++) {
      const blockStart = schedule.startTimes[i];
      const blockEnd = schedule.endTimes[i];
      const trainId = schedule.trainIds[i];

      // Skip if outside visible range
      if (blockEnd < startTime || blockStart > endTime) continue;

      // Skip if train is out of range
      if (trainId < 0 || trainId >= numRows) continue;

      // Calculate bucket range for this block
      const startBucket = Math.max(0, Math.floor((blockStart - startTime) / bucketDuration));
      const endBucket = Math.min(numBuckets - 1, Math.floor((blockEnd - startTime) / bucketDuration));

      // Increment density for each affected bucket
      for (let b = startBucket; b <= endBucket; b++) {
        const idx = trainId * numBuckets + b;
        this.densityData[idx]++;
      }
    }
  }

  /**
   * Update the texture from density data.
   */
  private updateTexture(): void {
    const { numBuckets, numRows, rowHeight } = this.config;
    const viewport = getViewportState();

    // Find max density for normalization
    let maxDensity = 1;
    for (let i = 0; i < this.densityData.length; i++) {
      if (this.densityData[i] > maxDensity) {
        maxDensity = this.densityData[i];
      }
    }

    // Create RGBA pixel data
    const pixelData = new Uint8Array(numBuckets * numRows * 4);

    for (let row = 0; row < numRows; row++) {
      for (let bucket = 0; bucket < numBuckets; bucket++) {
        const density = this.densityData[row * numBuckets + bucket];
        const normalizedDensity = density / maxDensity;

        // Map to color index (0-7)
        const colorIdx = Math.min(7, Math.floor(normalizedDensity * 8));
        const color = HEATMAP_COLORS[colorIdx];

        // Extract RGB components
        const r = (color >> 16) & 0xff;
        const g = (color >> 8) & 0xff;
        const b = color & 0xff;

        // Write to pixel array
        const pixelIdx = (row * numBuckets + bucket) * 4;
        pixelData[pixelIdx] = r;
        pixelData[pixelIdx + 1] = g;
        pixelData[pixelIdx + 2] = b;
        pixelData[pixelIdx + 3] = 255;
      }
    }

    // Destroy old texture
    if (this.texture) {
      this.texture.destroy(true);
    }

    // Create new texture from pixel data
    this.texture = Texture.from({
      resource: pixelData,
      width: numBuckets,
      height: numRows,
      scaleMode: SCALE_MODES.NEAREST,
    });

    // Update or create sprite
    if (this.sprite) {
      this.sprite.texture = this.texture;
    } else {
      this.sprite = new Sprite(this.texture);
      this.container.addChild(this.sprite);
    }

    // Scale sprite to fill viewport
    this.sprite.width = viewport.width;
    this.sprite.height = numRows * rowHeight;
  }

  /**
   * Resize the layer.
   */
  resize(width: number, height: number): void {
    if (this.sprite) {
      this.sprite.width = width;
      // Height stays based on numRows × rowHeight
    }
    this.markDirty();
  }

  /**
   * Destroy the layer and release resources.
   */
  destroy(): void {
    if (this.texture) {
      this.texture.destroy(true);
      this.texture = null;
    }

    if (this.sprite) {
      this.sprite.destroy();
      this.sprite = null;
    }

    this.container.destroy({ children: true });
  }
}

